window['edit'] = function edit(targetID){
	targetedID = targetID

	jQuery.get("api/SZ_SETUPANDMAINTENANCE_LETTERPHRASE_API?phraseinfo=1&lpm_value="+targetedID, function(data) {
		
		$('#lpm_value').val(data.LPM_VALUE);
		$('#lpm_value_desc_bm').val(data.LPM_VALUE_DESC_BM);
		$('#lpm_value_desc').val(data.LPM_VALUE_DESC);
	
		$('#letter_pharse').modal('show');
	})
}

//=================================================== save med
btnSaveMed = function (){

	// console.log('MASUK');
	if(formValidate('#letter_pharse')){
		$('#btn_saveMed').toggleSpinner()
		var detail = $('#letter_pharse :input').serializeJson()
		$.post("api/SZ_SETUPANDMAINTENANCE_LETTERPHRASE_API?save_med=1", {detail: detail}, function(data){
			if(data.status=='ok'){
				showModal({
					type: "alert",
					content: data.successmessage, 
					size: "sm",

					onclick: function() {
						location.reload();
					}
				});
				$('#dt_list').DataTable().ajax.reload();
				$('#btn_saveMed').toggleSpinner()
			}
			else{
				$('#btn_saveMed').toggleSpinner()
				showModal({
					type: "danger",
					content: data.msgError,
					size: "sm",
				})
			}
		}, "json");	
	}
	else{
		$('#btn_saveMed').toggleSpinner()
		showModal({
			type: "danger",
			content: LANG_VALIDATE_VALUEMISSING,
			size: "sm",
		})
	}
}
